-- ============================================================
-- gakudo baseline schema (consolidated)
--
-- Pre-launch (production users = 0) baseline, generated by
-- concatenating the previous 13 migrations in apply order:
--
--   00001_initial_schema           — core tables (profiles, children, attendances, etc.)
--   00002_rls_policies             — RLS for all application tables
--   00003_storage_policies         — RLS for storage.objects (photos, documents)
--   00004_site_pages_metadata      — site_pages.metadata column + seed
--   00005_attachments              — attachments table for announcements/news
--   00006_entrance_role            — extend role CHECK to allow 'entrance'
--   00007_inquiries                — public inquiry form table
--   00008_instagram_posts          — admin-curated Instagram URL list
--   00009_attendance_summary_rpc   — get_attendance_summary RPC
--   00010_announcement_recipients  — targeted announcement model + can_view_announcement()
--   00011_perf_indexes             — performance indexes
--   00012_rate_limit_log           — IP/email rate limiting table
--   00013_site_news_revisions      — site_news edit history (audit trail)
--
-- The original 13 migration files were removed in this commit. Per-
-- file history is preserved in git log (`git log --diff-filter=D` for
-- the deletion commit). New schema changes go in fresh
-- 00002_*.sql, 00003_*.sql, ... files appended on top of this baseline.
-- ============================================================


-- ============================================================
-- Section from: 00001_initial_schema.sql
-- ============================================================

-- ============================================================
-- 学童保育管理システム 初期スキーマ
-- ============================================================

-- updated_at 自動更新トリガー関数
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- ============================================================
-- プロフィール（Supabase Auth と連携）
-- ============================================================
CREATE TABLE IF NOT EXISTS profiles (
  id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  email TEXT NOT NULL,
  name TEXT NOT NULL,
  role TEXT NOT NULL CHECK (role IN ('parent', 'teacher', 'admin')),
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

CREATE TRIGGER trg_profiles_updated_at
  BEFORE UPDATE ON profiles
  FOR EACH ROW
  EXECUTE FUNCTION update_updated_at_column();

-- ============================================================
-- 児童
-- ============================================================
CREATE TABLE IF NOT EXISTS children (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  grade INTEGER NOT NULL CHECK (grade BETWEEN 1 AND 6),
  qr_code TEXT UNIQUE NOT NULL,
  qr_active BOOLEAN DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

CREATE TRIGGER trg_children_updated_at
  BEFORE UPDATE ON children
  FOR EACH ROW
  EXECUTE FUNCTION update_updated_at_column();

-- ============================================================
-- 児童と保護者の多対多リレーション
-- ============================================================
CREATE TABLE IF NOT EXISTS child_parents (
  child_id UUID REFERENCES children(id) ON DELETE CASCADE,
  parent_id UUID REFERENCES profiles(id) ON DELETE CASCADE,
  PRIMARY KEY (child_id, parent_id)
);

-- ============================================================
-- 入退室記録
-- ============================================================
CREATE TABLE IF NOT EXISTS attendances (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  child_id UUID NOT NULL REFERENCES children(id) ON DELETE CASCADE,
  type TEXT NOT NULL CHECK (type IN ('enter', 'exit')),
  method TEXT NOT NULL CHECK (method IN ('qr', 'manual')),
  recorded_at TIMESTAMPTZ DEFAULT now(),
  recorded_by UUID REFERENCES profiles(id)
);

CREATE INDEX IF NOT EXISTS idx_attendances_child_date
  ON attendances (child_id, recorded_at);

-- ============================================================
-- お知らせ
-- ============================================================
CREATE TABLE IF NOT EXISTS announcements (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  title TEXT NOT NULL,
  body TEXT NOT NULL,
  posted_by UUID NOT NULL REFERENCES profiles(id),
  created_at TIMESTAMPTZ DEFAULT now()
);

-- ============================================================
-- お知らせ既読管理
-- ============================================================
CREATE TABLE IF NOT EXISTS announcement_reads (
  announcement_id UUID REFERENCES announcements(id) ON DELETE CASCADE,
  user_id UUID REFERENCES profiles(id) ON DELETE CASCADE,
  read_at TIMESTAMPTZ DEFAULT now(),
  PRIMARY KEY (announcement_id, user_id)
);

-- ============================================================
-- 写真
-- ============================================================
CREATE TABLE IF NOT EXISTS photos (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  storage_path TEXT NOT NULL,
  thumbnail_path TEXT,
  caption TEXT,
  event_name TEXT,
  visibility TEXT NOT NULL DEFAULT 'private' CHECK (visibility IN ('private', 'public')),
  uploaded_by UUID NOT NULL REFERENCES profiles(id),
  created_at TIMESTAMPTZ DEFAULT now()
);

-- ============================================================
-- 書類・ドキュメント
-- ============================================================
CREATE TABLE IF NOT EXISTS documents (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  title TEXT NOT NULL,
  file_path TEXT NOT NULL,
  category TEXT NOT NULL,
  uploaded_by UUID NOT NULL REFERENCES profiles(id),
  created_at TIMESTAMPTZ DEFAULT now()
);

-- ============================================================
-- 延長保育料金ルール
-- ============================================================
CREATE TABLE IF NOT EXISTS billing_rules (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  regular_end_time TIME NOT NULL,
  rate_per_unit INTEGER NOT NULL,
  unit_minutes INTEGER NOT NULL DEFAULT 30,
  effective_from DATE NOT NULL,
  created_by UUID NOT NULL REFERENCES profiles(id),
  created_at TIMESTAMPTZ DEFAULT now()
);

-- ============================================================
-- 月次請求
-- ============================================================
CREATE TABLE IF NOT EXISTS monthly_bills (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  child_id UUID NOT NULL REFERENCES children(id),
  year_month TEXT NOT NULL,
  total_extended_minutes INTEGER NOT NULL DEFAULT 0,
  total_amount INTEGER NOT NULL DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'draft' CHECK (status IN ('draft', 'confirmed')),
  confirmed_at TIMESTAMPTZ,
  confirmed_by UUID REFERENCES profiles(id),
  created_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE (child_id, year_month)
);

-- ============================================================
-- 公開サイト 固定ページ
-- ============================================================
CREATE TABLE IF NOT EXISTS site_pages (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  slug TEXT UNIQUE NOT NULL,
  title TEXT NOT NULL,
  content TEXT NOT NULL,
  updated_at TIMESTAMPTZ DEFAULT now(),
  updated_by UUID REFERENCES profiles(id)
);

CREATE TRIGGER trg_site_pages_updated_at
  BEFORE UPDATE ON site_pages
  FOR EACH ROW
  EXECUTE FUNCTION update_updated_at_column();

-- ============================================================
-- 公開サイト ニュース
-- ============================================================
CREATE TABLE IF NOT EXISTS site_news (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  title TEXT NOT NULL,
  body TEXT NOT NULL,
  published_at TIMESTAMPTZ DEFAULT now(),
  created_by UUID REFERENCES profiles(id)
);

-- ============================================================
-- 通知設定
-- ============================================================
CREATE TABLE IF NOT EXISTS notification_preferences (
  user_id UUID PRIMARY KEY REFERENCES profiles(id) ON DELETE CASCADE,
  method TEXT NOT NULL DEFAULT 'email' CHECK (method IN ('push', 'email', 'both', 'off'))
);

-- ============================================================
-- プッシュ通知サブスクリプション
-- ============================================================
CREATE TABLE IF NOT EXISTS push_subscriptions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,
  subscription JSONB NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- ============================================================
-- Section from: 00002_rls_policies.sql
-- ============================================================

-- ============================================================
-- Row Level Security ポリシー
-- ============================================================

-- ============================================================
-- ヘルパー関数
-- ============================================================

-- ユーザーロール取得
CREATE OR REPLACE FUNCTION public.get_user_role()
RETURNS TEXT AS $$
  SELECT role FROM public.profiles WHERE id = auth.uid()
$$ LANGUAGE sql SECURITY DEFINER STABLE;

-- 管理者判定
CREATE OR REPLACE FUNCTION public.is_admin()
RETURNS BOOLEAN AS $$
  SELECT EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role = 'admin')
$$ LANGUAGE sql SECURITY DEFINER STABLE;

-- スタッフ判定（教員または管理者）
CREATE OR REPLACE FUNCTION public.is_staff()
RETURNS BOOLEAN AS $$
  SELECT EXISTS (SELECT 1 FROM public.profiles WHERE id = auth.uid() AND role IN ('teacher', 'admin'))
$$ LANGUAGE sql SECURITY DEFINER STABLE;

-- ============================================================
-- 全テーブル RLS 有効化
-- ============================================================
ALTER TABLE profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE children ENABLE ROW LEVEL SECURITY;
ALTER TABLE child_parents ENABLE ROW LEVEL SECURITY;
ALTER TABLE attendances ENABLE ROW LEVEL SECURITY;
ALTER TABLE announcements ENABLE ROW LEVEL SECURITY;
ALTER TABLE announcement_reads ENABLE ROW LEVEL SECURITY;
ALTER TABLE photos ENABLE ROW LEVEL SECURITY;
ALTER TABLE documents ENABLE ROW LEVEL SECURITY;
ALTER TABLE billing_rules ENABLE ROW LEVEL SECURITY;
ALTER TABLE monthly_bills ENABLE ROW LEVEL SECURITY;
ALTER TABLE site_pages ENABLE ROW LEVEL SECURITY;
ALTER TABLE site_news ENABLE ROW LEVEL SECURITY;
ALTER TABLE notification_preferences ENABLE ROW LEVEL SECURITY;
ALTER TABLE push_subscriptions ENABLE ROW LEVEL SECURITY;

-- ============================================================
-- profiles（プロフィール）
-- ============================================================

-- 認証済みユーザーは全プロフィールを閲覧可能（名前表示等に必要）
CREATE POLICY "profiles_select_authenticated"
  ON profiles FOR SELECT
  TO authenticated
  USING (true);

-- 挿入はトリガーまたは管理者（service role）のみ
-- RLS ポリシーなし = デフォルト拒否

-- 自分のプロフィールを更新可能、管理者は全員分を更新可能
CREATE POLICY "profiles_update_own_or_admin"
  ON profiles FOR UPDATE
  TO authenticated
  USING (id = auth.uid() OR is_admin())
  WITH CHECK (id = auth.uid() OR is_admin());

-- ============================================================
-- children（児童）
-- ============================================================

-- スタッフは全児童を閲覧可能、保護者は自分の子どものみ
CREATE POLICY "children_select"
  ON children FOR SELECT
  TO authenticated
  USING (
    is_staff()
    OR id IN (SELECT child_id FROM child_parents WHERE parent_id = auth.uid())
  );

-- 登録・更新・削除はスタッフのみ
CREATE POLICY "children_insert_staff"
  ON children FOR INSERT
  TO authenticated
  WITH CHECK (is_staff());

CREATE POLICY "children_update_staff"
  ON children FOR UPDATE
  TO authenticated
  USING (is_staff())
  WITH CHECK (is_staff());

CREATE POLICY "children_delete_staff"
  ON children FOR DELETE
  TO authenticated
  USING (is_staff());

-- ============================================================
-- child_parents（児童と保護者のリレーション）
-- ============================================================

-- スタッフは全件閲覧可能、保護者は自分の行のみ
CREATE POLICY "child_parents_select"
  ON child_parents FOR SELECT
  TO authenticated
  USING (
    is_staff()
    OR parent_id = auth.uid()
  );

-- 登録・削除はスタッフのみ
CREATE POLICY "child_parents_insert_staff"
  ON child_parents FOR INSERT
  TO authenticated
  WITH CHECK (is_staff());

CREATE POLICY "child_parents_delete_staff"
  ON child_parents FOR DELETE
  TO authenticated
  USING (is_staff());

-- ============================================================
-- attendances（入退室記録）
-- ============================================================

-- スタッフは全件閲覧可能、保護者は自分の子どもの記録のみ
CREATE POLICY "attendances_select"
  ON attendances FOR SELECT
  TO authenticated
  USING (
    is_staff()
    OR child_id IN (SELECT child_id FROM child_parents WHERE parent_id = auth.uid())
  );

-- 登録はスタッフのみ（教員・管理者が記録）
CREATE POLICY "attendances_insert_staff"
  ON attendances FOR INSERT
  TO authenticated
  WITH CHECK (is_staff());

-- 更新・削除は管理者のみ
CREATE POLICY "attendances_update_admin"
  ON attendances FOR UPDATE
  TO authenticated
  USING (is_admin())
  WITH CHECK (is_admin());

CREATE POLICY "attendances_delete_admin"
  ON attendances FOR DELETE
  TO authenticated
  USING (is_admin());

-- ============================================================
-- announcements（お知らせ）
-- ============================================================

-- 認証済みユーザーは全件閲覧可能
CREATE POLICY "announcements_select_authenticated"
  ON announcements FOR SELECT
  TO authenticated
  USING (true);

-- 投稿はスタッフのみ
CREATE POLICY "announcements_insert_staff"
  ON announcements FOR INSERT
  TO authenticated
  WITH CHECK (is_staff());

-- 更新は管理者または投稿者本人（スタッフに限る）
CREATE POLICY "announcements_update"
  ON announcements FOR UPDATE
  TO authenticated
  USING (is_admin() OR (posted_by = auth.uid() AND is_staff()))
  WITH CHECK (is_admin() OR (posted_by = auth.uid() AND is_staff()));

-- 削除は管理者または投稿者本人（スタッフに限る）
CREATE POLICY "announcements_delete"
  ON announcements FOR DELETE
  TO authenticated
  USING (is_admin() OR (posted_by = auth.uid() AND is_staff()));

-- ============================================================
-- announcement_reads（お知らせ既読管理）
-- ============================================================

-- 自分の既読またはスタッフは全件閲覧可能
CREATE POLICY "announcement_reads_select"
  ON announcement_reads FOR SELECT
  TO authenticated
  USING (
    user_id = auth.uid()
    OR is_staff()
  );

-- 自分の既読のみ登録可能
CREATE POLICY "announcement_reads_insert_own"
  ON announcement_reads FOR INSERT
  TO authenticated
  WITH CHECK (user_id = auth.uid());

-- 削除は管理者のみ
CREATE POLICY "announcement_reads_delete_admin"
  ON announcement_reads FOR DELETE
  TO authenticated
  USING (is_admin());

-- ============================================================
-- photos（写真）
-- ============================================================

-- スタッフは全件閲覧可能、認証済みユーザーはプライベート写真を閲覧可能、公開写真は全員閲覧可能
CREATE POLICY "photos_select_authenticated"
  ON photos FOR SELECT
  TO authenticated
  USING (
    is_staff()
    OR visibility = 'public'
    OR visibility = 'private'
  );

-- 公開写真は匿名ユーザーも閲覧可能
CREATE POLICY "photos_select_anon"
  ON photos FOR SELECT
  TO anon
  USING (visibility = 'public');

-- アップロードはスタッフのみ
CREATE POLICY "photos_insert_staff"
  ON photos FOR INSERT
  TO authenticated
  WITH CHECK (is_staff());

-- 更新は管理者またはアップロード者
CREATE POLICY "photos_update"
  ON photos FOR UPDATE
  TO authenticated
  USING (is_admin() OR uploaded_by = auth.uid())
  WITH CHECK (is_admin() OR uploaded_by = auth.uid());

-- 削除は管理者またはアップロード者
CREATE POLICY "photos_delete"
  ON photos FOR DELETE
  TO authenticated
  USING (is_admin() OR uploaded_by = auth.uid());

