  WITH CHECK (is_admin() OR uploaded_by = auth.uid());

-- 削除は管理者またはアップロード者
CREATE POLICY "documents_delete"
  ON documents FOR DELETE
  TO authenticated
  USING (is_admin() OR uploaded_by = auth.uid());

