-- ============================================================
-- Section from: 00009_attendance_summary_rpc.sql
-- ============================================================

-- RPC function: returns anonymous attendance summary counts for today
-- Accessible by any authenticated user (parents can see how many children are present)
CREATE OR REPLACE FUNCTION get_attendance_summary()
RETURNS JSON
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  total_children INT;
  entered_count INT;
  exited_count INT;
  jst_start TIMESTAMPTZ;
  jst_end TIMESTAMPTZ;
BEGIN
  -- Calculate today's range in JST (UTC+9)
  jst_start := date_trunc('day', now() AT TIME ZONE 'Asia/Tokyo') AT TIME ZONE 'Asia/Tokyo';
  jst_end := jst_start + interval '1 day';

  SELECT COUNT(*) INTO total_children FROM children;

  -- Get latest attendance type per child today
  WITH latest AS (
    SELECT DISTINCT ON (child_id) child_id, type
    FROM attendances
    WHERE recorded_at >= jst_start AND recorded_at < jst_end
    ORDER BY child_id, recorded_at DESC
  )
  SELECT
    COUNT(*) FILTER (WHERE type = 'enter'),
    COUNT(*) FILTER (WHERE type = 'exit')
  INTO entered_count, exited_count
  FROM latest;

  RETURN json_build_object(
    'total', total_children,
    'entered', COALESCE(entered_count, 0),
    'exited', COALESCE(exited_count, 0),
    'none', total_children - COALESCE(entered_count, 0) - COALESCE(exited_count, 0)
  );
END;
$$;

GRANT EXECUTE ON FUNCTION get_attendance_summary() TO authenticated;

-- ============================================================
-- Section from: 00010_announcement_recipients.sql
-- ============================================================

-- ============================================================
-- お知らせの送信対象（全員／個別ユーザー）
-- ============================================================
--
-- これまで announcements は全認証ユーザーへ一斉公開されていた。
-- 先生・管理者が「全員」または「個別ユーザー」を選んで送れるよう、
-- 対象テーブルを追加する。
--
-- recipient_type:
--   'all'  : 全保護者向け（recipient_user_id は NULL）
--   'user' : 個別ユーザー（recipient_user_id に profiles.id を格納）
--
-- 1つの announcement に対して 'user' 行を複数挿入することで
-- 「保護者A・Bだけ」のような個別宛先を表現できる。
-- 'all' と 'user' の併用は不要なため 'all' は1行に限定する。

CREATE TABLE IF NOT EXISTS announcement_recipients (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  announcement_id UUID NOT NULL REFERENCES announcements(id) ON DELETE CASCADE,
  recipient_type TEXT NOT NULL CHECK (recipient_type IN ('all', 'user')),
  recipient_user_id UUID REFERENCES profiles(id) ON DELETE CASCADE,
  created_at TIMESTAMPTZ DEFAULT now(),
  CONSTRAINT announcement_recipients_value_check CHECK (
    (recipient_type = 'all'  AND recipient_user_id IS NULL)
    OR (recipient_type = 'user' AND recipient_user_id IS NOT NULL)
  )
);

CREATE INDEX IF NOT EXISTS idx_announcement_recipients_announcement
  ON announcement_recipients (announcement_id);

CREATE INDEX IF NOT EXISTS idx_announcement_recipients_user
  ON announcement_recipients (recipient_user_id)
  WHERE recipient_user_id IS NOT NULL;

-- 同一お知らせ内での重複行を防止
CREATE UNIQUE INDEX IF NOT EXISTS uniq_announcement_recipients_all
  ON announcement_recipients (announcement_id)
  WHERE recipient_type = 'all';

CREATE UNIQUE INDEX IF NOT EXISTS uniq_announcement_recipients_user
  ON announcement_recipients (announcement_id, recipient_user_id)
  WHERE recipient_type = 'user';

-- ============================================================
-- 既存お知らせのバックフィル（全件 'all' 扱い）
-- ============================================================
INSERT INTO announcement_recipients (announcement_id, recipient_type)
  SELECT a.id, 'all'
  FROM announcements a
  WHERE NOT EXISTS (
    SELECT 1 FROM announcement_recipients ar WHERE ar.announcement_id = a.id
  );

-- ============================================================
-- 閲覧権限ヘルパー
-- ============================================================
-- announcement_recipients の RLS が announcements の SELECT 内で再帰的に
-- 効くと厄介なので、SECURITY DEFINER の関数で対象判定を一括化する。
CREATE OR REPLACE FUNCTION public.can_view_announcement(p_announcement_id UUID)
RETURNS BOOLEAN AS $$
  SELECT public.is_staff()
    OR EXISTS (
      SELECT 1
      FROM public.announcement_recipients ar
      WHERE ar.announcement_id = p_announcement_id
        AND (
          ar.recipient_type = 'all'
          OR (ar.recipient_type = 'user' AND ar.recipient_user_id = auth.uid())
        )
    )
$$ LANGUAGE sql SECURITY DEFINER STABLE;

-- ============================================================
-- announcements の SELECT を「対象判定」ベースに差し替え
-- ============================================================
DROP POLICY IF EXISTS "announcements_select_authenticated" ON announcements;

CREATE POLICY "announcements_select_targeted"
  ON announcements FOR SELECT
  TO authenticated
  USING (public.can_view_announcement(id));

-- ============================================================
-- announcement_recipients の RLS
-- ============================================================
ALTER TABLE announcement_recipients ENABLE ROW LEVEL SECURITY;

-- スタッフは全件、保護者は自分が閲覧可能なお知らせの行だけ閲覧可
CREATE POLICY "announcement_recipients_select"
  ON announcement_recipients FOR SELECT
  TO authenticated
  USING (
    public.is_staff()
    OR public.can_view_announcement(announcement_id)
  );

-- 登録・更新・削除はスタッフのみ
CREATE POLICY "announcement_recipients_insert_staff"
  ON announcement_recipients FOR INSERT
  TO authenticated
  WITH CHECK (public.is_staff());

CREATE POLICY "announcement_recipients_update_staff"
  ON announcement_recipients FOR UPDATE
  TO authenticated
  USING (public.is_staff())
  WITH CHECK (public.is_staff());

CREATE POLICY "announcement_recipients_delete_staff"
  ON announcement_recipients FOR DELETE
  TO authenticated
  USING (public.is_staff());

-- ============================================================
-- Section from: 00011_perf_indexes.sql
-- ============================================================

-- ============================================================
-- Phase 1-C: Performance indexes for hot lookup paths
-- ============================================================
--
-- Plain CREATE INDEX (not CONCURRENTLY) because Supabase migrations
-- run inside a transaction. For production rollout on a hot table,
-- run an ad-hoc CREATE INDEX CONCURRENTLY first, then this migration
-- becomes a no-op via IF NOT EXISTS.
--
-- Coverage rationale:
--
-- 1. child_parents(parent_id)
--    Backed query: src/lib/announcements/recipients-server.ts
--      .from("child_parents").select(...).in("parent_id", ids)
--    The PRIMARY KEY is (child_id, parent_id) so parent_id alone is
--    not indexable via the PK. Without this, IN-list lookups scan.
--
-- 2. push_subscriptions(user_id)
--    Backed query: src/lib/notifications/send.ts (sendPushNotifications)
--      .from("push_subscriptions").select(...).in("user_id", userIds)
--    Currently no user_id index — every fan-out scans the whole table.
--    With Phase 1-A's parallel push, this scan would be the new
--    bottleneck.
--
-- 3. monthly_bills(year_month, status)
--    Backed queries: src/app/(dashboard)/billing/actions.ts
--      .eq("year_month", ym).eq("status", "draft")
--    UNIQUE (child_id, year_month) covers (year_month) only as the
--    second column. Composite (year_month, status) speeds the
--    confirm/list flow.
--
-- 4. announcement_reads(user_id)
--    Backed query: src/components/nav/get-badge-counts.ts (unread)
--    Plus exists() lookups for unread badges.
--    PRIMARY KEY is (announcement_id, user_id) so user_id alone is
--    not indexable from the PK; this index covers per-user lookups.
--
-- Skipped (already covered):
--   - inquiries(status): created in 00007_inquiries.sql
--   - attendances(child_id, recorded_at): created in
--     00001_initial_schema.sql (the asc index also serves desc scans).
--   - announcement_recipients(*): created in
--     00010_announcement_recipients.sql.

CREATE INDEX IF NOT EXISTS idx_child_parents_parent
  ON child_parents (parent_id);

CREATE INDEX IF NOT EXISTS idx_push_subscriptions_user
  ON push_subscriptions (user_id);

CREATE INDEX IF NOT EXISTS idx_monthly_bills_yearmonth_status
  ON monthly_bills (year_month, status);

CREATE INDEX IF NOT EXISTS idx_announcement_reads_user
  ON announcement_reads (user_id);

-- ============================================================
-- Section from: 00012_rate_limit_log.sql
-- ============================================================

-- ============================================================
-- Phase 2-A.4: Self-hosted rate limit ledger
-- ============================================================
--
-- Stores one row per "hit" for a given key (e.g. an IP address, an
-- email, or a composite of both). Callers count hits within a sliding
-- window via lib/ratelimit/check.ts to decide allow/deny.
--
-- Why a table instead of an external service:
--   - The plan explicitly favors self-hosted over @upstash/ratelimit.
--   - Supabase Postgres is the single source of truth we already trust
--     for everything else; we don't have to deploy or pay for another
--     piece of infra.
--   - Volume is low for the call sites we'll wire up (contact form,
--     password reset). A B-tree on (key, hit_at) handles them comfortably.
--
-- Hygiene:
--   - rate_limit_log_cleanup() drops rows older than 24 hours.
--   - Called best-effort from check.ts on a small percentage of
--     requests so we don't need pg_cron in the dev stack. Production
--     can also schedule it explicitly via Supabase scheduled jobs.

CREATE TABLE IF NOT EXISTS rate_limit_log (
  id BIGSERIAL PRIMARY KEY,
  key TEXT NOT NULL,
  hit_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_rate_limit_log_key_hit_at
  ON rate_limit_log (key, hit_at DESC);

-- Service-role-only access; this table is internal plumbing and must
-- not be exposed to anon/authenticated traffic via PostgREST.
ALTER TABLE rate_limit_log ENABLE ROW LEVEL SECURITY;

-- No CREATE POLICY → with RLS enabled, only the service-role bypass
-- can read/write. This is intentional.

CREATE OR REPLACE FUNCTION public.rate_limit_log_cleanup()
RETURNS void AS $$
  DELETE FROM rate_limit_log
   WHERE hit_at < now() - INTERVAL '24 hours'
$$ LANGUAGE sql SECURITY DEFINER;

REVOKE ALL ON FUNCTION public.rate_limit_log_cleanup() FROM PUBLIC;

-- ============================================================
-- Section from: 00013_site_news_revisions.sql
-- ============================================================

-- Edit history for site_news.
--
-- The HP管理 > お知らせ管理 (admin/site/news) screen previously only let
-- admins create and delete entries; once posted there was no way to fix
-- a typo without losing audit trail. This migration adds:
--
--   1. site_news.updated_at / updated_by — tracks the latest edit on
--      the live row. Auto-maintained by a BEFORE UPDATE trigger so the
--      app code only has to set updated_by.
--   2. site_news_revisions — append-only snapshot table written
--      whenever the live row is updated. Captures the title, body, and
--      attachment metadata as it was BEFORE the change so admins can
--      see what each edit replaced.
--
-- The attachment list is denormalized into a JSONB column on the
-- revision so the snapshot keeps showing the file names + sizes that
-- existed at the time of the edit, even after the underlying
-- attachment rows have been deleted from the live table. The actual
-- file objects in storage are removed when an admin deletes the
-- attachment from the live row, so the JSONB metadata is the only
-- record kept (file_path is preserved but signed URLs to it stop
-- working once the storage object is gone — that's an accepted
-- trade-off since the user explicitly chose to remove the file).

ALTER TABLE site_news
  ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  ADD COLUMN IF NOT EXISTS updated_by UUID REFERENCES profiles(id);

-- Auto-bump updated_at on every UPDATE. Existing rows get NOW() once
-- the trigger first fires; the DEFAULT above seeds them up front so
-- the column is sortable from day one.
CREATE OR REPLACE FUNCTION site_news_set_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS site_news_set_updated_at_trigger ON site_news;
CREATE TRIGGER site_news_set_updated_at_trigger
  BEFORE UPDATE ON site_news
  FOR EACH ROW
  EXECUTE FUNCTION site_news_set_updated_at();

-- Append-only revision history.
CREATE TABLE IF NOT EXISTS site_news_revisions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  news_id UUID NOT NULL REFERENCES site_news(id) ON DELETE CASCADE,
  title TEXT NOT NULL,
  body TEXT NOT NULL,
  -- Snapshot of attachments at the time of the edit. Shape:
  --   [{ id, file_name, file_path, file_size, mime_type }]
  attachments JSONB NOT NULL DEFAULT '[]'::jsonb,
  edited_by UUID REFERENCES profiles(id),
  edited_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS site_news_revisions_news_id_idx
  ON site_news_revisions (news_id, edited_at DESC);

-- RLS: revisions are an admin-only audit trail. Public users and
-- non-admin staff have no business reading prior versions of news copy.
ALTER TABLE site_news_revisions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "site_news_revisions_admin_select"
  ON site_news_revisions FOR SELECT
  TO authenticated
  USING (is_admin());

-- Inserts come exclusively from the updateNews server action which
-- runs with admin auth gated by withAuth + RLS; explicit policy keeps
-- the table append-only from the application side too.
CREATE POLICY "site_news_revisions_admin_insert"
  ON site_news_revisions FOR INSERT
  TO authenticated
  WITH CHECK (is_admin());
